enum HeroClass {
  brute,
  guardian,
  illusionist,
  mechanologist,
  merchant,
  ninja,
  ranger,
  runeblade,
  warrior,
  wizard,
  assassin,
  bard,
  necromancer,
  shapeshifter,
  adjudicator,
  generic,
}

enum HeroTalent {
  none,
  draconic,
  earth,
  elemental,
  ice,
  light,
  lightning,
  shadow,
  royal,
  mystic,
}

class HeroData {
  final String id;
  final String name;
  final String title;
  final HeroClass heroClass;
  final List<HeroTalent> talents;
  final bool isYoung;
  final int intellect;
  final int health;
  final String? customImagePath;
  /// Free-form rules text users can attach to a custom hero. Empty for
  /// stock heroes from the bundled library.
  final String cardText;

  const HeroData({
    required this.id,
    required this.name,
    this.title = '',
    required this.heroClass,
    this.talents = const [HeroTalent.none],
    required this.isYoung,
    required this.intellect,
    required this.health,
    this.customImagePath,
    this.cardText = '',
  });

  String get displayName => title.isNotEmpty ? '$name, $title' : name;

  /// Preferred character-art path. Falls back to card scan via [resolveArtPath]
  /// when no art file exists.
  String get artPath => 'assets/images/heroes/$id.jpg';

}

